import requests

def test_manager_create_team_missing_mandatory_field():
    BASE_URL = 'http://localhost:8000'
    token = <obtain_manager_token>

    missing_name = {
        'description': 'Test team',
        'manager_id': <manager_id>
    }
    resp = requests.post(
        f'{BASE_URL}/api/teams',
        json=missing_name,
        headers={'Authorization': f'Bearer {token}'}
    )
    assert resp.status_code == 400
    assert 'name' in resp.json()['message'].lower()

    missing_description = {
        'name': 'Test team',
        'manager_id': <manager_id>
    }
    resp = requests.post(
        f'{BASE_URL}/api/teams',
        json=missing_description,
        headers={'Authorization': f'Bearer {token}'}
    )
    assert resp.status_code == 400
    assert 'description' in resp.json()['message'].lower()

