def test_manager_create_team_unauthenticated_forbidden():
    BASE_URL = 'http://localhost:8000'

    payload = {
        'name': 'Test Team',
        'description': 'Test',
        'manager_id': 'mgr123'
    }

    resp = requests.post(
        f'{BASE_URL}/api/teams',
        json=payload
    )
    assert resp.status_code == 401

    resp = requests.post(
        f'{BASE_URL}/api/teams',
        json=payload,
        headers={'Authorization': 'Bearer invalid_token'}
    )
    assert resp.status_code == 401

